import{_ as s,o as a,c as o,aw as e}from"./chunks/framework.Dq2onT5h.js";const t=JSON.parse('{"title":"ABCI RPC Reference","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ABCI RPC Reference | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"reference/api/abci-rpc.md","filePath":"reference/api/abci-rpc.md","lastUpdated":1772446570000}');const n=s({name:"reference/api/abci-rpc.md"},[["render",function(s,t,n,l,p,c){return a(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="abci-rpc-reference" tabindex="-1">ABCI RPC Reference <a class="header-anchor" href="#abci-rpc-reference" aria-label="Permalink to &quot;ABCI RPC Reference&quot;">​</a></h1><p>CometBFT-compatible RPC endpoints provided by ev-abci.</p><h2 id="query-methods" tabindex="-1">Query Methods <a class="header-anchor" href="#query-methods" aria-label="Permalink to &quot;Query Methods&quot;">​</a></h2><h3 id="abci-query" tabindex="-1">/abci_query <a class="header-anchor" href="#abci-query" aria-label="Permalink to &quot;/abci_query&quot;">​</a></h3><p>Query application state.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/abci_query?path=&quot;/store/bank/key&quot;&amp;data=0x...</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><p><strong>Response:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">jsonrpc</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">2.0</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">result</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">    &quot;</span><span style="color:#94EEFF;">response</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">code</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 0</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">value</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">base64encodedvalue</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">height</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">1000</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#767676;">    }</span></span>\n<span class="line"><span style="color:#767676;">  },</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">id</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 1</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><h3 id="block" tabindex="-1">/block <a class="header-anchor" href="#block" aria-label="Permalink to &quot;/block&quot;">​</a></h3><p>Get block at height.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/block?height=100</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="block-results" tabindex="-1">/block_results <a class="header-anchor" href="#block-results" aria-label="Permalink to &quot;/block_results&quot;">​</a></h3><p>Get block results (tx results, events).</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/block_results?height=100</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="commit" tabindex="-1">/commit <a class="header-anchor" href="#commit" aria-label="Permalink to &quot;/commit&quot;">​</a></h3><p>Get commit (signatures) at height.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/commit?height=100</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="validators" tabindex="-1">/validators <a class="header-anchor" href="#validators" aria-label="Permalink to &quot;/validators&quot;">​</a></h3><p>Get validator set (returns sequencer in Evolve).</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/validators?height=100</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="status" tabindex="-1">/status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;/status&quot;">​</a></h3><p>Get node status.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/status</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="genesis" tabindex="-1">/genesis <a class="header-anchor" href="#genesis" aria-label="Permalink to &quot;/genesis&quot;">​</a></h3><p>Get genesis document.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/genesis</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="health" tabindex="-1">/health <a class="header-anchor" href="#health" aria-label="Permalink to &quot;/health&quot;">​</a></h3><p>Health check.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/health</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h2 id="transaction-methods" tabindex="-1">Transaction Methods <a class="header-anchor" href="#transaction-methods" aria-label="Permalink to &quot;Transaction Methods&quot;">​</a></h2><h3 id="broadcast-tx-async" tabindex="-1">/broadcast_tx_async <a class="header-anchor" href="#broadcast-tx-async" aria-label="Permalink to &quot;/broadcast_tx_async&quot;">​</a></h3><p>Broadcast transaction, return immediately.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/broadcast_tx_async?tx=0x...</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="broadcast-tx-sync" tabindex="-1">/broadcast_tx_sync <a class="header-anchor" href="#broadcast-tx-sync" aria-label="Permalink to &quot;/broadcast_tx_sync&quot;">​</a></h3><p>Broadcast transaction, wait for CheckTx.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/broadcast_tx_sync?tx=0x...</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="broadcast-tx-commit" tabindex="-1">/broadcast_tx_commit <a class="header-anchor" href="#broadcast-tx-commit" aria-label="Permalink to &quot;/broadcast_tx_commit&quot;">​</a></h3><p>Broadcast transaction, wait for inclusion.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/broadcast_tx_commit?tx=0x...</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="tx" tabindex="-1">/tx <a class="header-anchor" href="#tx" aria-label="Permalink to &quot;/tx&quot;">​</a></h3><p>Get transaction by hash.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/tx?hash=0x...</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h3 id="tx-search" tabindex="-1">/tx_search <a class="header-anchor" href="#tx-search" aria-label="Permalink to &quot;/tx_search&quot;">​</a></h3><p>Search transactions.</p><p><strong>Request:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:26657/tx_search?query=&quot;tx.height=100&quot;</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><h2 id="websocket" tabindex="-1">WebSocket <a class="header-anchor" href="#websocket" aria-label="Permalink to &quot;WebSocket&quot;">​</a></h2><h3 id="subscribe" tabindex="-1">/subscribe <a class="header-anchor" href="#subscribe" aria-label="Permalink to &quot;/subscribe&quot;">​</a></h3><p>Subscribe to events.</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">jsonrpc</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">2.0</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">method</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">subscribe</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">params</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#94EEFF;">query</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">tm.event=&#39;NewBlock&#39;</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">},</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">id</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 1</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><p>Event types:</p><ul><li><code>NewBlock</code> — New block committed</li><li><code>Tx</code> — Transaction included</li><li><code>NewBlockHeader</code> — New block header</li></ul><h2 id="unsupported-methods" tabindex="-1">Unsupported Methods <a class="header-anchor" href="#unsupported-methods" aria-label="Permalink to &quot;Unsupported Methods&quot;">​</a></h2><p>These CometBFT methods are not supported in ev-abci:</p><table tabindex="0"><thead><tr><th>Method</th><th>Reason</th></tr></thead><tbody><tr><td><code>/consensus_state</code></td><td>No BFT consensus</td></tr><tr><td><code>/dump_consensus_state</code></td><td>No BFT consensus</td></tr><tr><td><code>/net_info</code></td><td>Different P2P model</td></tr><tr><td><code>/unconfirmed_txs</code></td><td>Different mempool</td></tr><tr><td><code>/num_unconfirmed_txs</code></td><td>Different mempool</td></tr></tbody></table><h2 id="port" tabindex="-1">Port <a class="header-anchor" href="#port" aria-label="Permalink to &quot;Port&quot;">​</a></h2><p>Default: <code>26657</code></p><p>Configure:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">--evnode.rpc.address</span><span style="color:#BFF3C2;"> tcp://0.0.0.0:26657</span></span></code></pre></div>',71)])])}]]);export{t as __pageData,n as default};
